    persist({ ...data, [matchId]: { ...current, ersatzSpieler: list } });
    const opponent = matches.find((m) => m.id === matchId)?.opponent || "Spiel";
    const roundLabel = ROUNDS.find((r) => r.id === round)?.label || round;
